args.sparql:
SELECT ?series ?seriesLabel WHERE {
  ?series wdt:P161 wd:Q200261;
        wdt:P31/wdt:P279* wd:Q5398426;
        wdt:P580 ?startDate;
        rdfs:label ?seriesLabel.
  FILTER (LANG(?seriesLabel) = "en")
  FILTER (?startDate > "2011-05-13T00:00:00Z"^^xsd:dateTime)
}
ORDER BY ?startDate
LIMIT 1
